153→        if (tokenTextSize != FONT_DEFAULT) {
154→            holder.vName.setTextSize(TypedValue.COMPLEX_UNIT_SP, tokenTextSize);
155→        }
156→
157→        RecipientAdapter.setContactPhotoOrPlaceholder(getContext(), holder.vContactPhoto, recipient);
158→
159→        boolean hasCryptoProvider = cryptoProvider != null;
160→        if (!hasCryptoProvider) {
161→            holder.hideCryptoState();
162→            return;
163→        }
164→
165→        boolean isAvailable = recipient.cryptoStatus == RecipientCryptoStatus.AVAILABLE_TRUSTED ||
166→                recipient.cryptoStatus == RecipientCryptoStatus.AVAILABLE_UNTRUSTED;
167→        if (!showAdvancedInfo) {
168→            holder.showSimpleCryptoState(isAvailable, showCryptoEnabled);
169→        } else {
170→            boolean isVerified = recipient.cryptoStatus == RecipientCryptoStatus.AVAILABLE_TRUSTED;
171→            holder.showAdvancedCryptoState(isAvailable, isVerified);
172→        }
