import assertk.assertThat
import assertk.assertions.isEmpty
import kotlin.test.Test

/**
 * Tests for validating that email addresses with invalid hostnames are rejected.
 * See: https://github.com/thundernest/k-9/issues/XXXX
 */
class UserInputEmailAddressParserInvalidHostnameTest {
    private val parser = UserInputEmailAddressParser()

    @Test
    fun `address ending with slash should be rejected`() {
        val addresses = parser.parse("user@gmail.com/")

        assertThat(addresses).isEmpty()
    }

    @Test
    fun `address with slash in hostname should be rejected`() {
        val addresses = parser.parse("user@gmail/com")

        assertThat(addresses).isEmpty()
    }

    @Test
    fun `address ending with backslash should be rejected`() {
        val addresses = parser.parse("user@gmail.com\\")

        assertThat(addresses).isEmpty()
    }

    @Test
    fun `address with angle bracket in hostname should be rejected`() {
        val addresses = parser.parse("user@gmail.com>")

        assertThat(addresses).isEmpty()
    }

    @Test
    fun `address ending with dot should be rejected`() {
        val addresses = parser.parse("user@gmail.com.")

        assertThat(addresses).isEmpty()
    }

    @Test
    fun `address ending with hyphen should be rejected`() {
        val addresses = parser.parse("user@gmail.com-")

        assertThat(addresses).isEmpty()
    }

    @Test
    fun `valid address should be accepted`() {
        val addresses = parser.parse("user@gmail.com")

        assertThat(addresses).transform { it.map { addr -> addr.address } }
            .equals(listOf("user@gmail.com"))
    }

    @Test
    fun `address with hyphen in hostname should be accepted`() {
        val addresses = parser.parse("user@my-domain.com")

        assertThat(addresses).transform { it.map { addr -> addr.address } }
            .equals(listOf("user@my-domain.com"))
    }

    @Test
    fun `address with IP literal should be accepted`() {
        val addresses = parser.parse("user@[192.168.1.1]")

        assertThat(addresses).transform { it.map { addr -> addr.address } }
            .equals(listOf("user@[192.168.1.1]"))
    }
}
